head.b:skin:
:root {
  --navy: #0d1b2a;
  --navy-mid: #1b2d3e;
  --blue: #1a6fbf;
  --blue-light: #2e8de0;
  --accent: #e63946;
  --gold: #f4a261;
  --white: #ffffff;
  --off-white: #f8f9fa;
  --gray-100: #f1f3f5;
  --gray-200: #e9ecef;
  --gray-400: #adb5bd;
  --gray-600: #6c757d;
  --gray-800: #343a40;
  --text: #1a1a2e;
  --shadow: 0 4px 24px rgba(0,0,0,0.10);
  --shadow-hover: 0 8px 32px rgba(0,0,0,0.18);
  --radius: 10px;
  --transition: all 0.28s cubic-bezier(0.4,0,0.2,1);
}
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: 'DM Sans', sans-serif; background: var(--off-white); color: var(--text); font-size: 15px; line-height: 1.6; overflow-x: hidden; }
a { text-decoration: none; color: inherit; }
img { max-width: 100%; height: auto; display: block; }

/* TOP BAR */
#top-bar { background: var(--navy); color: var(--gray-400); font-size: 12px; padding: 7px 0; border-bottom: 2px solid var(--blue); }
.top-bar-inner { max-width: 1200px; margin: 0 auto; padding: 0 20px; display: flex; justify-content: space-between; align-items: center; }
.top-bar-links a { color: var(--gray-400); margin-left: 18px; font-size: 12px; transition: var(--transition); }
.top-bar-links a:hover { color: var(--white); }

/* HEADER */
#header { background: var(--white); box-shadow: 0 2px 12px rgba(0,0,0,0.08); position: sticky; top: 0; z-index: 1000; }
.header-inner { max-width: 1200px; margin: 0 auto; padding: 0 20px; display: flex; align-items: center; justify-content: space-between; height: 70px; }
.logo-area img { height: 55px; width: auto; }
.logo-text { font-family: 'Playfair Display', serif; font-size: 28px; font-weight: 900; color: var(--navy); }
.logo-text span { color: var(--blue-light); }

/* NAV */
#main-nav { background: var(--navy); position: relative; z-index: 999; }
.nav-inner { max-width: 1200px; margin: 0 auto; padding: 0 20px; display: flex; align-items: center; justify-content: space-between; }
.nav-links { display: flex; list-style: none; }
.nav-links li a { display: block; color: var(--gray-200); font-size: 13px; font-weight: 500; letter-spacing: 0.8px; text-transform: uppercase; padding: 15px 16px; transition: var(--transition); position: relative; }
.nav-links li a::after { content: ''; position: absolute; bottom: 0; left: 50%; right: 50%; height: 3px; background: var(--blue-light); transition: var(--transition); }
.nav-links li a:hover { color: var(--white); }
.nav-links li a:hover::after { left: 0; right: 0; }
.nav-search input { background: var(--navy-mid); border: 1px solid rgba(255,255,255,0.1); color: var(--white); padding: 7px 14px; border-radius: 20px; font-size: 13px; width: 180px; transition: var(--transition); }
.nav-search input:focus { outline: none; border-color: var(--blue-light); width: 220px; }
.nav-search input::placeholder { color: var(--gray-400); }

/* BREAKING TICKER */
#breaking-ticker { background: var(--accent); padding: 9px 0; overflow: hidden; }
.ticker-inner { max-width: 1200px; margin: 0 auto; padding: 0 20px; display: flex; align-items: center; gap: 16px; }
.ticker-label { background: var(--white); color: var(--accent); font-size: 11px; font-weight: 700; letter-spacing: 1px; text-transform: uppercase; padding: 3px 10px; border-radius: 3px; white-space: nowrap; flex-shrink: 0; }
.ticker-scroll { overflow: hidden; flex: 1; }
.ticker-text { color: var(--white); font-size: 13px; font-weight: 500; white-space: nowrap; animation: ticker-move 30s linear infinite; }
@keyframes ticker-move { 0% { transform: translateX(100%); } 100% { transform: translateX(-100%); } }

/* MAIN LAYOUT */
#main-wrapper { max-width: 1200px; margin: 0 auto; padding: 30px 20px; display: grid; grid-template-columns: 1fr 300px; gap: 30px; }

/* CATEGORY SECTIONS */
.sc-section { margin-bottom: 40px; opacity: 0; transform: translateY(20px); transition: opacity 0.5s ease, transform 0.5s ease; }
.sc-section.visible { opacity: 1; transform: translateY(0); }
.section-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 18px; padding-bottom: 12px; border-bottom: 3px solid var(--gray-200); position: relative; }
.section-header::before { content: ''; position: absolute; bottom: -3px; left: 0; width: 60px; height: 3px; background: var(--blue); }
.section-title { font-family: 'Playfair Display', serif; font-size: 20px; font-weight: 700; color: var(--navy); display: flex; align-items: center; gap: 8px; }
.section-more { font-size: 12px; font-weight: 600; color: var(--blue); letter-spacing: 0.5px; text-transform: uppercase; transition: var(--transition); display: flex; align-items: center; gap: 4px; }
.section-more:hover { color: var(--accent); gap: 8px; }

/* POST CARDS */
.posts-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 18px; }
.post-card { background: var(--white); border-radius: var(--radius); overflow: hidden; box-shadow: var(--shadow); transition: var(--transition); cursor: pointer; display: block; }
.post-card:hover { transform: translateY(-4px); box-shadow: var(--shadow-hover); }
.post-card-img { width: 100%; height: 160px; object-fit: cover; background: var(--gray-100); display: flex; align-items: center; justify-content: center; color: var(--gray-400); font-size: 30px; overflow: hidden; }
.post-card-img img { width: 100%; height: 160px; object-fit: cover; }
.post-card-body { padding: 14px; }
.post-card-cat { font-size: 10px; font-weight: 700; letter-spacing: 1px; text-transform: uppercase; color: var(--blue); margin-bottom: 6px; }
.post-card-title { font-family: 'Playfair Display', serif; font-size: 15px; font-weight: 700; color: var(--navy); line-height: 1.4; margin-bottom: 8px; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }
.post-card-date { font-size: 11px; color: var(--gray-400); }
.loading-msg { color: var(--gray-400); font-size: 13px; padding: 20px 0; text-align: center; }

/* DISCOVER SECTION */
.discover-section { background: linear-gradient(135deg, var(--navy) 0%, var(--navy-mid) 100%); border-radius: 14px; padding: 24px; margin-bottom: 40px; position: relative; overflow: hidden; opacity: 0; transform: translateY(20px); transition: opacity 0.5s ease, transform 0.5s ease; }
.discover-section.visible { opacity: 1; transform: translateY(0); }
.discover-section::before { content: '?'; position: absolute; right: 20px; top: 50%; transform: translateY(-50%); font-size: 120px; font-family: 'Playfair Display', serif; font-weight: 900; color: rgba(255,255,255,0.04); line-height: 1; }
.discover-section .section-header { border-bottom-color: rgba(255,255,255,0.1); }
.discover-section .section-title { color: var(--white); }
.discover-section .section-more { color: var(--gold); }
.discover-section .post-card { background: rgba(255,255,255,0.07); border: 1px solid rgba(255,255,255,0.1); }
.discover-section .post-card:hover { background: rgba(255,255,255,0.12); }
.discover-section .post-card-title { color: var(--white); }
.discover-section .post-card-date { color: rgba(255,255,255,0.4); }
.discover-section .post-card-cat { color: var(--gold); }

/* AD SLOT */
.ad-slot { background: var(--gray-100); border: 2px dashed var(--gray-200); border-radius: var(--radius); display: flex; align-items: center; justify-content: center; color: var(--gray-400); font-size: 12px; letter-spacing: 1px; text-transform: uppercase; margin-bottom: 30px; min-height: 90px; }

/* SIDEBAR */
.sidebar-widget { background: var(--white); border-radius: var(--radius); overflow: hidden; box-shadow: var(--shadow); margin-bottom: 24px; }
.widget-header { background: var(--navy); color: var(--white); font-family: 'Playfair Display', serif; font-size: 14px; font-weight: 700; padding: 12px 16px; display: flex; align-items: center; gap: 8px; }
.widget-header i { color: var(--blue-light); font-size: 13px; }
.widget-body { padding: 16px; }
.category-list { list-style: none; }
.category-list li { border-bottom: 1px solid var(--gray-100); }

/* SCROLL TO TOP */
#scroll-top { position: fixed; bottom: 28px; right: 28px; width: 44px; height: 44px; background: var(--blue); color: var(--white); border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 16px; cursor: pointer; box-shadow: 0 4px 16px rgba(30,111,191,0.4); transition: var(--transition); opacity: 0; pointer-events: none; z-index: 9999; }
#scroll-top.visible { opacity: 1; pointer-events: all; }
#scroll-top:hover { background: var(--accent); transform: translateY(-3px); }

/* FOOTER */
#footer { background: var(--navy); color: var(--gray-400); padding: 40px 0 0; margin-top: 40px; }
.footer-inner { max-width: 1200px; margin: 0 auto; padding: 0 20px 30px; display: grid; grid-template-columns: 2fr 1fr 1fr 1fr; gap: 30px; }
.footer-brand .logo-text { color: var(--white); font-size: 24px; }
.footer-brand p { font-size: 13px; line-height: 1.7; margin-top: 10px; }
.footer-col h4 { color: var(--white); font-size: 13px; font-weight: 600; letter-spacing: 1px; text-transform: uppercase; margin-bottom: 14px; padding-bottom: 8px; border-bottom: 2px solid var(--blue); display: inline-block; }
.footer-col ul { list-style: none; }
.footer-col ul li { margin-bottom: 8px; }
.footer-col ul li a { color: var(--gray-400); font-size: 13px; transition: var(--transition); }
.footer-col ul li a:hover { color: var(--white); }
.footer-bottom { background: rgba(0,0,0,0.3); text-align: center; padding: 14px 20px; font-size: 12px; border-top: 1px solid rgba(255,255,255,0.05); }
.footer-bottom a { color: var(--blue-light); }

/* SINGLE POST */
.post-content-wrapper { background: var(--white); border-radius: var(--radius); padding: 30px; box-shadow: var(--shadow); }
.post-title { font-family: 'Playfair Display', serif; font-size: 32px; font-weight: 900; color: var(--navy); line-height: 1.3; margin-bottom: 14px; }
.post-meta { display: flex; align-items: center; gap: 16px; color: var(--gray-400); font-size: 13px; padding-bottom: 14px; border-bottom: 1px solid var(--gray-200); margin-bottom: 20px; }
.post-featured-img { width: 100%; border-radius: var(--radius); margin-bottom: 24px; max-height: 420px; object-fit: cover; }
.post-body { font-size: 16px; line-height: 1.85; color: var(--gray-800); }
.post-body p { margin-bottom: 18px; }
.post-body h2 { font-family: 'Playfair Display', serif; font-size: 22px; color: var(--navy); margin: 28px 0 12px; }

/* PAGE */
.page-content-wrapper { background: var(--white); border-radius: var(--radius); padding: 30px; box-shadow: var(--shadow); }
.page-title { font-family: 'Playfair Display', serif; font-size: 28px; font-weight: 900; color: var(--navy); margin-bottom: 20px; padding-bottom: 14px; border-bottom: 3px solid var(--gray-200); }

#main-wrapper2 { max-width: 1200px; margin: 0 auto; padding: 30px 20px; display: grid; grid-template-columns: 1fr 300px; gap: 30px; }
#sidebar2 { }
/* MOBILE */
@media (max-width: 768px) {
  #main-wrapper { grid-template-columns: 1fr; }
  .posts-grid { grid-template-columns: 1fr 1fr; }
  .footer-inner { grid-template-columns: 1fr 1fr; }
  .nav-links { display: none; }
  .post-title { font-size: 24px; }
}
@media (max-width: 480px) {
  .posts-grid { grid-template-columns: 1fr; }
  .footer-inner { grid-template-columns: 1fr; }
}

/* POST LIST CARDS - Label/Search pages */
.post-list-card { background: var(--white); border-radius: var(--radius); overflow: hidden; box-shadow: var(--shadow); margin-bottom: 24px; display: flex; gap: 0; transition: var(--transition); }
.post-list-card:hover { transform: translateY(-3px); box-shadow: var(--shadow-hover); }
.post-list-img { width: 280px; min-width: 280px; height: 180px; overflow: hidden; display: block; background: var(--gray-100); }
.post-list-img img { width: 100%; height: 100%; object-fit: cover; transition: var(--transition); }
.post-list-img:hover img { transform: scale(1.05); }
.post-list-img-placeholder { width: 100%; height: 100%; display: flex; align-items: center; justify-content: center; color: var(--gray-400); font-size: 36px; }
.post-list-body { padding: 20px; flex: 1; display: flex; flex-direction: column; justify-content: space-between; }
.post-list-labels { margin-bottom: 8px; }
.post-list-cat { font-size: 10px; font-weight: 700; letter-spacing: 1px; text-transform: uppercase; color: var(--white); background: var(--blue); padding: 3px 10px; border-radius: 20px; margin-right: 6px; }
.post-list-title { font-family: 'Playfair Display', serif; font-size: 20px; font-weight: 700; color: var(--navy); line-height: 1.4; margin-bottom: 10px; }
.post-list-title a { color: var(--navy); transition: var(--transition); }
.post-list-title a:hover { color: var(--blue); }
.post-list-snippet { font-size: 14px; color: var(--gray-600); line-height: 1.6; margin-bottom: 14px; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }
.post-list-meta { display: flex; align-items: center; gap: 16px; font-size: 12px; color: var(--gray-400); }
.post-list-readmore { margin-left: auto; background: var(--blue); color: var(--white); padding: 7px 16px; border-radius: 20px; font-size: 12px; font-weight: 600; display: flex; align-items: center; gap: 6px; transition: var(--transition); }
.post-list-readmore:hover { background: var(--accent); gap: 10px; }
@media (max-width: 600px) { .post-list-card { flex-direction: column; } .post-list-img { width: 100%; min-width: 100%; height: 200px; } }

body.script:
//
var BLOG_URL = 'https://www.scrollcorner.com/';

function fetchPosts(label, containerId, catColor, catName) {
  var container = document.getElementById(containerId);
  var url = BLOG_URL + 'feeds/posts/default/-/' + label + '?alt=json&max-results=3&fields=entry(title,published,link,media:thumbnail,content,summary)';

  var timer = setTimeout(function() {
    if(container && container.innerHTML.indexOf('Loading') !== -1) {
      container.innerHTML = '<div class="loading-msg">No posts yet in this category.</div>';
    }
  }, 8000);

  fetch(url)
    .then(function(r) { return r.json(); })
    .then(function(data) {
      clearTimeout(timer);
      renderPosts(data, containerId, catColor, catName);
    })
    .catch(function() {
      clearTimeout(timer);
      if(container) container.innerHTML = '<div class="loading-msg">No posts yet in this category.</div>';
    });
}

function extractImage(entry) {
  // Try media thumbnail first
  if (entry.media$thumbnail) {
    var src = entry.media$thumbnail.url;
    src = src.replace('/s72-c/', '/s400-c/');
    src = src.replace('/s1600/', '/s400/');
    return src;
  }
  // Try extracting from post content
  if (entry.content && entry.content.$t) {
    var match = entry.content.$t.match(/<img[^>]+src=["']([^"']+)["'][^>]*>/i);
    if (match) return match[1];
  }
  // Try summary
  if (entry.summary && entry.summary.$t) {
    var match2 = entry.summary.$t.match(/<img[^>]+src=["']([^"']+)["'][^>]*>/i);
    if (match2) return match2[1];
  }
  return '';
}

function renderPosts(data, containerId, catColor, catName) {
  var container = document.getElementById(containerId);
  if (!container) return;
  var entries = (data.feed && data.feed.entry) ? data.feed.entry : [];
  if (entries.length === 0) {
    container.innerHTML = '<div class="loading-msg">No posts yet in this category.</div>';
    return;
  }
  var html = '';
  entries.forEach(function(entry) {
    var title = entry.title.$t;
    var url = '';
    for (var i = 0; i < entry.link.length; i++) {
      if (entry.link[i].rel === 'alternate') { url = entry.link[i].href; break; }
    }
    var date = entry.published.$t.substring(0, 10);
    var img = extractImage(entry);
    html += '<a class="post-card" href="' + url + '">';
    html += '<div class="post-card-img">';
    if (img) { html += '<img src="' + img + '" alt="' + title.replace(/"/g,"'") + '" loading="lazy"/>'; }
    else { html += '<i class="fas fa-newspaper"></i>'; }
    html += '</div>';
    html += '<div class="post-card-body">';
    html += '<div class="post-card-cat" style="color:' + catColor + '">' + catName + '</div>';
    html += '<div class="post-card-title">' + title + '</div>';
    html += '<div class="post-card-date"><i class="far fa-calendar"></i> ' + date + '</div>';
    html += '</div></a>';
  });
  container.innerHTML = html;
}

// Load all sections
fetchPosts('World-News', 'posts-world', '#e63946', 'World News');
fetchPosts('Technology', 'posts-tech', '#2e8de0', 'Technology');
fetchPosts('Finance', 'posts-finance', '#2a9d8f', 'Finance');
fetchPosts('Science', 'posts-science', '#06d6a0', 'Science');
fetchPosts('Entertainment', 'posts-ent', '#9b5de5', 'Entertainment');
fetchPosts('Sports', 'posts-sports', '#f77f00', 'Sports');

// Discover - random category
var cats = [
  {label:'World-News', color:'#e63946', name:'World News'},
  {label:'Technology', color:'#2e8de0', name:'Technology'},
  {label:'Finance', color:'#2a9d8f', name:'Finance'},
  {label:'Science', color:'#06d6a0', name:'Science'},
  {label:'Entertainment', color:'#9b5de5', name:'Entertainment'},
  {label:'Sports', color:'#f77f00', name:'Sports'}
];
var rc = cats[Math.floor(Math.random() * cats.length)];
var discoverLink = document.getElementById('discover-link');
if (discoverLink) discoverLink.href = '/search/label/' + rc.label;
fetchPosts(rc.label, 'posts-discover', rc.color, '&#127922; ' + rc.name);

// Scroll to top
var scrollBtn = document.getElementById('scroll-top');
window.addEventListener('scroll', function() {
  scrollBtn.classList.toggle('visible', window.pageYOffset > 300);
});
scrollBtn.addEventListener('click', function() {
  window.scrollTo({top: 0, behavior: 'smooth'});
});

// Animate sections on scroll
var sections = document.querySelectorAll('.sc-section, .discover-section');
var observer = new IntersectionObserver(function(entries) {
  entries.forEach(function(e) { if (e.isIntersecting) e.target.classList.add('visible'); });
}, {threshold: 0.1});
sections.forEach(function(s) { observer.observe(s); });
//
